'use client';

/**
 * Hook para métricas do dashboard principal
 */

import { useQuery } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { useSecretaryDoctors } from '@/hooks/useSecretaryDoctors';

interface DashboardMetrics {
    totalPipelineValue: number;
    totalClosedValue: number;
    activeDeals: number;
    wonDeals: number;
    lostDeals: number;
    conversionRate: number;
    totalContacts: number;
    dealsByStage: Record<string, { count: number; value: number }>;
    monthlyLeads: Array<{ month: string; leads: number }>;
    monthlyRevenue: Array<{ month: string; projected: number; closed: number }>;
    servicesInterest: Array<{ service: string; count: number }>;
    conversionByStage: Array<{ stage: string; conversion: number }>;
    recentDeals: Array<{
        id: string;
        title: string;
        value: number;
        stage: string;
        contact?: { full_name?: string };
    }>;
    financials: {
        revenue: number;
        expenses: number;
        balance: number;
        previousRevenue: number;
        previousExpenses: number;
        previousBalance: number;
    };
    monthlyFinancials: Array<{
        month: string;
        revenue: number;
        expenses: number;
        balance: number;
    }>;
}

const fetchDashboardMetrics = async (
    userId: string,
    isAdminOrDono: boolean,
    doctorIds?: string[]
): Promise<DashboardMetrics> => {
    const supabase = createClient();

    // Buscar deals com contatos
    let dealsQuery = supabase
        .from('crm_deals')
        .select(`
            *,
            contact:crm_contacts(*)
        `);

    // Aplicar filtros baseados no papel do usuário
    if (!isAdminOrDono) {
        if (doctorIds && doctorIds.length > 0) {
            const orConditions = doctorIds
                .map(id => `user_id.eq.${id},assigned_to.eq.${id}`)
                .join(',');
            dealsQuery = dealsQuery.or(orConditions);
        } else {
            dealsQuery = dealsQuery.or(`user_id.eq.${userId},assigned_to.eq.${userId}`);
        }
    }

    const { data: deals, error: dealsError } = await dealsQuery;

    if (dealsError) throw new Error(`Erro ao buscar deals: ${dealsError.message}`);

    const dealsData = (deals || []) as any[];

    // Buscar contatos
    let contactsQuery = supabase.from('crm_contacts').select('*');

    if (!isAdminOrDono) {
        if (doctorIds && doctorIds.length > 0) {
            contactsQuery = contactsQuery.in('user_id', doctorIds);
        } else {
            const contactIdsFromDeals = dealsData
                .map((d: any) => d.contact_id)
                .filter(Boolean);

            let orFilter = `user_id.eq.${userId}`;

            if (contactIdsFromDeals.length > 0) {
                const uniqueContactIds = [...new Set(contactIdsFromDeals)] as string[];
                orFilter += `,id.in.(${uniqueContactIds.join(',')})`;
            }

            contactsQuery = contactsQuery.or(orFilter);
        }
    }

    const { data: contacts, error: contactsError } = await contactsQuery;

    if (contactsError) throw new Error(`Erro ao buscar contatos: ${contactsError.message}`);

    const contactsData = contacts || [];

    // Buscar transações financeiras (Últimos 12 meses)
    const now = new Date();
    // const startOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
    // const startOfPreviousMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1).toISOString();
    const startOf12MonthsAgo = new Date(now.getFullYear(), now.getMonth() - 11, 1).toISOString();

    const { data: transactions } = await supabase
        .from('financial_transactions')
        .select('amount, type, status, transaction_date')
        .gte('transaction_date', startOf12MonthsAgo)
        .eq('status', 'concluida'); // Considerar apenas transações concluídas para o dashboard

    const transactionsData = transactions || [];

    // Calcular métricas financeiras (Current vs Previous Month)
    let currentRevenue = 0;
    let currentExpenses = 0;
    let previousRevenue = 0;
    let previousExpenses = 0;

    const currentMonthPrefix = now.toISOString().slice(0, 7); // YYYY-MM
    const previousMonthDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
    const previousMonthPrefix = previousMonthDate.toISOString().slice(0, 7); // YYYY-MM

    transactionsData.forEach((t: any) => {
        const val = Number(t.amount);
        const datePrefix = t.transaction_date.slice(0, 7);

        if (datePrefix === currentMonthPrefix) {
            if (t.type === 'entrada') currentRevenue += val;
            else if (t.type === 'saida') currentExpenses += val;
        } else if (datePrefix === previousMonthPrefix) {
            if (t.type === 'entrada') previousRevenue += val;
            else if (t.type === 'saida') previousExpenses += val;
        }
    });

    const financials = {
        revenue: currentRevenue,
        expenses: currentExpenses,
        balance: currentRevenue - currentExpenses,
        previousRevenue,
        previousExpenses,
        previousBalance: previousRevenue - previousExpenses
    };

    // Calcular métricas básicas
    const totalPipelineValue = dealsData.reduce((sum: number, deal: any) => {
        const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
        return sum + (value || 0);
    }, 0);

    const activeDeals = dealsData.filter(d =>
        !d.stage?.includes('fechado')
    ).length;

    const wonDeals = dealsData.filter(d =>
        d.stage === 'fechado_ganho'
    ).length;

    const lostDeals = dealsData.filter(d =>
        d.stage === 'fechado_perdido'
    ).length;

    const totalClosedValue = dealsData
        .filter(d => d.stage === 'fechado_ganho')
        .reduce((sum, deal) => {
            const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
            return sum + (value || 0);
        }, 0);

    const totalFinalized = wonDeals + lostDeals;
    const conversionRate = totalFinalized > 0
        ? Math.round((wonDeals / totalFinalized) * 100 * 100) / 100
        : 0;

    // Calcular deals por estágio
    const dealsByStage: Record<string, { count: number; value: number }> = {};
    const stages = ['lead_novo', 'qualificado', 'apresentacao', 'proposta', 'negociacao', 'fechado_ganho', 'fechado_perdido'];

    stages.forEach(stage => {
        const stageDeals = dealsData.filter(d => d.stage === stage);
        const stageValue = stageDeals.reduce((sum, deal) => {
            const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
            return sum + (value || 0);
        }, 0);

        dealsByStage[stage] = {
            count: stageDeals.length,
            value: stageValue
        };
    });

    // Gerar dados mensais (últimos 12 meses)
    const monthlyLeads = [];
    const monthlyRevenue = []; // CRM Revenue
    const monthlyFinancials = []; // Real Cash Flow
    const currentDate = new Date();

    for (let i = 11; i >= 0; i--) {
        const date = new Date(currentDate.getFullYear(), currentDate.getMonth() - i, 1);
        const monthName = date.toLocaleDateString('pt-BR', { month: 'short' });
        const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;

        // Leads
        const monthLeads = contactsData.filter((contact: any) =>
            contact.created_at?.startsWith(monthKey)
        ).length;

        // CRM Deals
        const monthDeals = dealsData.filter(deal =>
            deal.created_at?.startsWith(monthKey)
        );

        const monthProjected = monthDeals.reduce((sum, deal) => {
            const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
            return sum + (value || 0);
        }, 0);

        const monthClosed = monthDeals
            .filter(deal => deal.stage === 'fechado_ganho')
            .reduce((sum, deal) => {
                const value = typeof deal.value === 'string' ? parseFloat(deal.value) : deal.value;
                return sum + (value || 0);
            }, 0);

        // Financials (Cash Flow)
        const monthTransactions = transactionsData.filter((t: any) =>
            t.transaction_date?.startsWith(monthKey)
        );

        let mRevenue = 0;
        let mExpenses = 0;

        monthTransactions.forEach((t: any) => {
            const val = Number(t.amount);
            if (t.type === 'entrada') mRevenue += val;
            else if (t.type === 'saida') mExpenses += val;
        });

        monthlyLeads.push({ month: monthName, leads: monthLeads });
        monthlyRevenue.push({
            month: monthName,
            projected: monthProjected,
            closed: monthClosed
        });
        monthlyFinancials.push({
            month: monthName,
            revenue: mRevenue,
            expenses: mExpenses,
            balance: mRevenue - mExpenses
        });
    }

    // Interesse por serviços
    const servicesInterest: Array<{ service: string; count: number }> = [];
    const serviceCounts: Record<string, number> = {};

    contactsData.forEach((contact: any) => {
        const service = contact.procedure_id || contact.service_interest;
        if (service) {
            serviceCounts[service] = (serviceCounts[service] || 0) + 1;
        }
    });

    Object.entries(serviceCounts).forEach(([service, count]) => {
        servicesInterest.push({ service, count });
    });

    // Conversão por estágio
    const conversionByStage = [];
    const stageOrder = ['lead_novo', 'qualificado', 'apresentacao', 'proposta', 'negociacao'];

    for (let i = 0; i < stageOrder.length - 1; i++) {
        const currentStage = stageOrder[i];
        const nextStage = stageOrder[i + 1];

        const currentCount = dealsByStage[currentStage]?.count || 0;
        const nextCount = dealsByStage[nextStage]?.count || 0;

        const conversion = currentCount > 0
            ? Math.min((nextCount / currentCount) * 100, 100)
            : 0;
        conversionByStage.push({ stage: currentStage, conversion: Math.round(conversion * 10) / 10 });
    }

    // Últimos 5 deals atualizados
    const recentDeals = [...dealsData]
        .sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime())
        .slice(0, 5)
        .map(d => ({
            id: d.id,
            title: d.title,
            value: d.value,
            stage: d.stage,
            contact: d.contact
        }));

    return {
        totalPipelineValue,
        totalClosedValue,
        activeDeals,
        wonDeals,
        lostDeals,
        conversionRate,
        totalContacts: contactsData.length,
        dealsByStage,
        monthlyLeads,
        monthlyRevenue,
        servicesInterest,
        conversionByStage,
        recentDeals,
        financials,
        monthlyFinancials
    };
};

export function useDashboardMetrics() {
    const { user, loading: authLoading } = useAuth();
    const { profile, isSecretaria, isLoading: isLoadingProfile } = useUserProfile();
    const { doctorIds, isLoading: isLoadingDoctors } = useSecretaryDoctors();
    const isAdminOrDono = profile?.role === 'admin' || profile?.role === 'dono';

    const doctorIdsToUse = isSecretaria ? doctorIds : [];

    return useQuery({
        queryKey: ['dashboard-metrics', user?.id, profile?.role, doctorIdsToUse],
        queryFn: async () => {
            if (!user?.id) {
                throw new Error('Usuário não autenticado');
            }
            return await fetchDashboardMetrics(
                user.id,
                isAdminOrDono,
                doctorIdsToUse.length > 0 ? doctorIdsToUse : undefined
            );
        },
        enabled: !!user?.id && !!profile && !authLoading && !isLoadingProfile && (!isSecretaria || !isLoadingDoctors),
        staleTime: 10 * 60 * 1000,
        gcTime: 30 * 60 * 1000,
        refetchOnWindowFocus: false,
        retry: 1,
    });
}
