'use client';

import { useQuery } from '@tanstack/react-query';
import { useCallback } from 'react';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';

const EMPTY_ARRAY: string[] = [];

export interface LinkedDoctor {
    id: string;
    full_name: string | null;
    email: string;
    specialty?: string | null;
}

/**
 * Hook para buscar os medicos vinculados a uma secretaria
 */
export function useSecretaryDoctors() {
    const supabase = createClient();
    const { user, isSecretaria, isLoading: isLoadingProfile, profile } = useUserProfile();

    const {
        data,
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['secretary-doctors', user?.id],
        queryFn: async () => {
            if (!user?.id) return { doctorIds: [], doctors: [] };

            // 1. Fetch link IDs
            const { data: links, error: linkError } = await supabase
                .from('secretary_doctor_links')
                .select('doctor_id')
                .eq('secretary_id', user.id) as { data: { doctor_id: string }[] | null; error: Error | null };

            if (linkError) {
                console.error('[useSecretaryDoctors] Error fetching links:', linkError);
                return { doctorIds: [], doctors: [] };
            }

            if (!links || links.length === 0) {
                console.warn('[useSecretaryDoctors] No links found for secretary:', user.id);
                return { doctorIds: [], doctors: [] };
            }

            const doctorIds = links.map(l => l.doctor_id);

            // 2. Fetch doctor profiles
            const { data: doctorsData, error: profileError } = await supabase
                .from('profiles')
                .select('id, full_name, email')
                .in('id', doctorIds) as {
                    data: { id: string; full_name: string | null; email: string }[] | null;
                    error: Error | null;
                };

            if (profileError) {
                console.error('[useSecretaryDoctors] Error fetching profiles:', profileError);
                return { doctorIds, doctors: [] };
            }

            const doctors: LinkedDoctor[] = (doctorsData || []).map(doc => ({
                id: doc.id,
                full_name: doc.full_name,
                email: doc.email,
            }));

            return { doctorIds, doctors };
        },
        enabled: !!user?.id && !isLoadingProfile && isSecretaria,
        staleTime: 5 * 60 * 1000,
        gcTime: 10 * 60 * 1000,
    });

    return {
        doctorIds: data?.doctorIds || EMPTY_ARRAY,
        doctors: data?.doctors || [],
        isLoading: (isLoading && isSecretaria) || isLoadingProfile,
        error,
        refetch,
        isDoctorLinked: (doctorId: string) => data?.doctorIds.includes(doctorId) || false,
    };
}

/**
 * Hook para admins gerenciarem vinculos de secretarias
 */
export function useSecretaryDoctorLinks() {
    const supabase = createClient();
    const { user, isAdmin, profile } = useUserProfile();

    const { data: allLinks, isLoading, refetch } = useQuery({
        queryKey: ['all-secretary-doctor-links'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('secretary_doctor_links')
                .select(`
                    id,
                    secretary_id,
                    doctor_id,
                    created_at,
                    secretary:profiles!secretary_doctor_links_secretary_id_fkey (
                        id,
                        full_name,
                        email
                    ),
                    doctor:profiles!secretary_doctor_links_doctor_id_fkey (
                        id,
                        full_name,
                        email
                    )
                `);

            if (error) throw error;
            return (data || []) as Array<{
                id: string;
                secretary_id: string;
                doctor_id: string;
                created_at: string;
                secretary: { id: string; full_name: string | null; email: string } | null;
                doctor: { id: string; full_name: string | null; email: string } | null;
            }>;
        },
        enabled: !!user?.id && isAdmin,
        staleTime: 2 * 60 * 1000,
    });

    const createLink = async (secretaryId: string, doctorId: string) => {
        const { data, error } = await supabase
            .from('secretary_doctor_links')
            .insert({
                secretary_id: secretaryId,
                doctor_id: doctorId,
            } as never)
            .select()
            .single();

        if (error) throw error;
        await refetch();
        return data;
    };

    const removeLink = async (linkId: string) => {
        const { error } = await supabase
            .from('secretary_doctor_links')
            .delete()
            .eq('id', linkId);

        if (error) throw error;
        await refetch();
    };

    const updateSecretaryLinks = async (secretaryId: string, doctorIds: string[]) => {
        // First remove existing links
        await supabase
            .from('secretary_doctor_links')
            .delete()
            .eq('secretary_id', secretaryId);

        if (doctorIds.length > 0) {
            const links = doctorIds.map(doctorId => ({
                secretary_id: secretaryId,
                doctor_id: doctorId,
            }));

            const { error } = await supabase
                .from('secretary_doctor_links')
                .insert(links as never[]);

            if (error) throw error;
        }

        await refetch();
    };

    const getLinksForSecretary = useCallback((secretaryId: string) => {
        return allLinks?.filter(link => link.secretary_id === secretaryId) || [];
    }, [allLinks]);

    return {
        allLinks: allLinks || [],
        isLoading,
        createLink,
        removeLink,
        updateSecretaryLinks,
        getLinksForSecretary,
        refetch,
    };
}
