'use client';

import { useUserProfile } from '@/hooks/useUserProfile';
import { useDashboardMetrics } from '@/hooks/useDashboardMetrics';
import { formatCurrency } from '@/lib/currency';
import {
    TrendingUp,
    DollarSign,
    Users,
    Target,
    Calendar,
    AlertCircle,
    CheckCircle2,
    Briefcase,
    Activity
} from 'lucide-react';
import { VisionMetricCard } from './VisionMetricCard';
import { Skeleton } from '@/components/ui/skeleton';

interface SecretaryMetrics {
    todayAppointments: number;
    confirmedToday: number;
    pendingConfirmation: number;
}

export function VisionHeroMetrics() {
    const { isSecretaria, isVendedor, isLoading: isLoadingProfile } = useUserProfile();
    const { data: dashboardMetrics, isLoading: isLoadingDashboard } = useDashboardMetrics();

    const isLoading = isLoadingProfile || isLoadingDashboard;

    if (isLoading) {
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {[1, 2, 3].map((i) => (
                    <Skeleton key={i} className="h-40 w-full rounded-xl" />
                ))}
            </div>
        );
    }

    // Secretária - placeholder metrics (can be enhanced with real data later)
    if (isSecretaria) {
        const secretaryMetrics: SecretaryMetrics = {
            todayAppointments: 8,
            confirmedToday: 5,
            pendingConfirmation: 3
        };

        return (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <VisionMetricCard
                    title="Agenda Hoje"
                    value={secretaryMetrics.todayAppointments || 0}
                    icon={Calendar}
                    variant="purple"
                    description={`${secretaryMetrics.confirmedToday || 0} confirmadas`}
                    trend={{ value: 'Hoje', direction: 'neutral' }}
                />
                <VisionMetricCard
                    title="Confirmações Pendentes"
                    value={secretaryMetrics.pendingConfirmation || 0}
                    icon={AlertCircle}
                    variant="orange"
                    description="Precisam de contato"
                />
                <VisionMetricCard
                    title="Taxa de Confirmação"
                    value={`${((secretaryMetrics.confirmedToday / (secretaryMetrics.todayAppointments || 1)) * 100).toFixed(0)}%`}
                    icon={CheckCircle2}
                    variant="green"
                    description="Performance diária"
                />
            </div>
        );
    }

    // Vendedor
    if (isVendedor && dashboardMetrics) {
        return (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <VisionMetricCard
                    title="Pipeline Ativo"
                    value={dashboardMetrics.activeDeals || 0}
                    icon={Briefcase}
                    variant="blue"
                    description={formatCurrency(dashboardMetrics.totalPipelineValue || 0)}
                />
                <VisionMetricCard
                    title="Vendas Fechadas"
                    value={dashboardMetrics.wonDeals || 0}
                    icon={Target}
                    variant="green"
                    description={formatCurrency(dashboardMetrics.totalClosedValue || 0)}
                />
                <VisionMetricCard
                    title="Taxa de Conversão"
                    value={`${(dashboardMetrics.conversionRate || 0).toFixed(1)}%`}
                    icon={TrendingUp}
                    variant="cyan"
                    description="Média de conversão"
                />
            </div>
        );
    }

    // Admin/Dono (Default)
    const financials = dashboardMetrics?.financials || {
        revenue: 0,
        expenses: 0,
        balance: 0,
        previousRevenue: 0,
        previousExpenses: 0,
        previousBalance: 0
    };

    const calculateTrend = (current: number, previous: number) => {
        if (previous === 0) return { value: '100%', direction: 'neutral' as const };
        const percent = ((current - previous) / previous) * 100;
        return {
            value: `${Math.abs(percent).toFixed(1)}%`,
            direction: percent >= 0 ? 'up' as const : 'down' as const
        };
    };

    const revenueTrend = calculateTrend(financials.revenue, financials.previousRevenue);
    const expensesTrend = calculateTrend(financials.expenses, financials.previousExpenses);
    const balanceTrend = calculateTrend(financials.balance, financials.previousBalance);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <VisionMetricCard
                title="Receita Mensal"
                value={formatCurrency(financials.revenue)}
                icon={DollarSign}
                variant="green"
                trend={{
                    value: revenueTrend.value,
                    direction: revenueTrend.direction
                }}
                description="Entradas este mês"
            />

            <VisionMetricCard
                title="Despesas Mensais"
                value={formatCurrency(financials.expenses)}
                icon={TrendingUp} // Or proper expense icon
                variant="orange"
                trend={{
                    value: expensesTrend.value,
                    direction: expensesTrend.direction === 'up' ? 'down' : 'up'
                }}
                description="Saídas este mês"
            />

            <VisionMetricCard
                title="Saldo Líquido"
                value={formatCurrency(financials.balance)}
                icon={Activity}
                variant={financials.balance >= 0 ? "cyan" : "pink"}
                trend={{
                    value: balanceTrend.value,
                    direction: balanceTrend.direction
                }}
                description="Resultado do mês"
            />
        </div>
    );
}
